import { MakeLogicType, actions, connect, kea, listeners, path } from 'kea'

import { dataThemeLogic } from 'scenes/dataThemeLogic'

import type { DataColorThemeModel, DataColorThemeModelPayload } from '../../../types'
import { dataColorThemesModalLogic } from './dataColorThemeModalLogic'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface dataColorThemesLogicValues {
    defaultTheme: DataColorThemeModel | null // dataThemeLogic
    posthogTheme: DataColorThemeModel | null | undefined // dataThemeLogic
    themes: DataColorThemeModel[] | null // dataThemeLogic
    themesLoading: boolean // dataThemeLogic
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface dataColorThemesLogicActions {
    openModal: (theme: any) => {
        theme: any
    } // dataColorThemesModalLogic
    submitThemeSuccess: (theme: DataColorThemeModelPayload) => {
        theme: DataColorThemeModelPayload
    } // dataColorThemesModalLogic
    setThemes: (themes: any) => {
        themes: any
    } // dataThemeLogic
    selectTheme: (id: number | 'new' | null) => {
        id: number | 'new' | null
    }
}

export type dataColorThemesLogicType = MakeLogicType<dataColorThemesLogicValues, dataColorThemesLogicActions>

export const dataColorThemesLogic = kea<dataColorThemesLogicType>([
    path(['scenes', 'settings', 'environment', 'dataColorThemesLogic']),
    connect(() => ({
        values: [dataThemeLogic, ['themes', 'themesLoading', 'defaultTheme', 'posthogTheme']],
        actions: [dataColorThemesModalLogic, ['openModal', 'submitThemeSuccess'], dataThemeLogic, ['setThemes']],
    })),
    actions({
        selectTheme: (id: 'new' | number | null) => ({ id }),
    }),
    listeners(({ values, actions }) => ({
        selectTheme: ({ id }) => {
            // we're not yet initialized
            if (values.themes == null || values.posthogTheme == null || id == null) {
                return
            }

            if (id === 'new') {
                const { id, name, is_global, ...newTheme } = values.posthogTheme
                actions.openModal(newTheme)
            } else {
                const existingTheme = values.themes.find((theme) => theme.id === id)
                actions.openModal(existingTheme)
            }
        },
        submitThemeSuccess: ({ theme }) => {
            const existingTheme = values.themes!.find((t) => t.id === theme.id)
            if (existingTheme != null) {
                const updatedThemes = values.themes!.map((t) => (t.id === theme.id ? theme : t))
                actions.setThemes(updatedThemes)
            } else {
                actions.setThemes([...values.themes!, theme])
            }
        },
    })),
])
